  1	import { Flex, FlexItem, Text, TextVariants, Tooltip } from '@patternfly/react-core';
  2	import { InfoCircleIcon, TachometerAltIcon } from '@patternfly/react-icons';
  3	import _ from 'lodash';
  4	import * as React from 'react';
  5	import { useTranslation } from 'react-i18next';
  6	import { Record } from '../../api/ipfix';
  7	import { RecordType } from '../../model/flow-query';
  8	import { Warning } from '../../model/warnings';
  9	import { rangeToSeconds, TimeRange } from '../../utils/datetime';
 10	import { valueFormat } from '../../utils/format';
 11	import { BytesIcon, PacketsIcon } from '../icons';
 12	import StatsQuerySummary from './stats-query-summary';
 13	
 14	export interface FlowsQuerySummaryContentProps {
 15	  flows: Record[];
 16	  type: RecordType;
 17	  numQueries?: number;
 18	  limitReached: boolean;
 19	  range: number | TimeRange;
 20	  loading?: boolean;
 21	  lastRefresh?: Date;
 22	  lastDuration?: number;
 23	  warning?: Warning;
 24	  direction: 'row' | 'column';
 25	  className?: string;
 26	  isShowQuerySummary?: boolean;
 27	  toggleQuerySummary?: () => void;
 28	}
 29	
 30	export const FlowsQuerySummaryContent: React.FC<FlowsQuerySummaryContentProps> = ({
 31	  flows,
 32	  type,
 33	  numQueries,
 34	  limitReached,
 35	  range,
 36	  loading,
 37	  lastRefresh,
 38	  lastDuration,
 39	  warning,
 40	  direction,
 41	  className,
 42	  isShowQuerySummary,
 43	  toggleQuerySummary
 44	}) => {
 45	  const { t } = useTranslation('plugin__netobserv-plugin');
 46	  const filteredFlows = flows.filter(
 47	    r => !r.labels._RecordType || ['endConnection', 'flowLog'].includes(r.labels._RecordType)
 48	  );
 49	
 50	  const rangeInSeconds = rangeToSeconds(range);
 51	
 52	  const counters = React.useCallback(() => {
 53	    const bytes = filteredFlows.map(f => f.fields.Bytes || 0).reduce((a, b) => a + b, 0);
 54	    const packets = filteredFlows.map(f => f.fields.Packets || 0).reduce((a, b) => a + b, 0);
 55	
 56	    return (
 57	      <>
 58	        {bytes > 0 && (
 59	          <FlexItem>
 60	            <Tooltip content={<Text component={TextVariants.p}>{t('Filtered sum of bytes')}</Text>}>
 61	              <div className="stats-query-summary-container-with-icon">
 62	                <BytesIcon />
 63	                <Text id="bytesCount" component={TextVariants.p}>
 64	                  {valueFormat(bytes, 0, t('B'), limitReached)}
 65	                </Text>
 66	              </div>
 67	            </Tooltip>
 68	          </FlexItem>
 69	        )}
 70	        {packets > 0 && (
 71	          <FlexItem>
 72	            <Tooltip content={<Text component={TextVariants.p}>{t('Filtered sum of packets')}</Text>}>
 73	              <div className="stats-query-summary-container-with-icon">
 74	                <PacketsIcon />
 75	                <Text id="packetsCount" component={TextVariants.p}>
 76	                  {valueFormat(packets, 0, t('Packets'), limitReached, true)}
 77	                </Text>
 78	              </div>
 79	            </Tooltip>
 80	          </FlexItem>
 81	        )}
 82	        {bytes > 0 && (
 83	          <FlexItem>
 84	            <Tooltip content={<Text component={TextVariants.p}>{t('Filtered average speed')}</Text>}>
 85	              <div className="stats-query-summary-container-with-icon">
 86	                <TachometerAltIcon />
 87	                <Text id="bytesPerSecondsCount" component={TextVariants.p}>
 88	                  {valueFormat(bytes / rangeInSeconds, 2, t('Bps'), limitReached)}
 89	                </Text>
 90	              </div>
 91	            </Tooltip>
 92	          </FlexItem>
 93	        )}
 94	      </>
 95	    );
 96	  }, [filteredFlows, limitReached, rangeInSeconds, t]);
 97	
 98	  return (
 99	    <Flex
100	      id="query-summary-content"
101	      className={`${className} ${direction === 'row' ? 'center' : ''}`}
102	      direction={{ default: direction }}
103	    >
104	      {direction === 'row' && (
105	        <FlexItem>
106	          <Text id="query-summary-title" component={TextVariants.h4}>
107	            {t('Summary')}
108	          </Text>
109	        </FlexItem>
110	      )}
111	      <StatsQuerySummary
112	        detailed={direction === 'column'}
113	        loading={loading}
114	        lastRefresh={lastRefresh}
115	        lastDuration={lastDuration}
116	        numQueries={numQueries}
117	        warning={warning}
118	      />
119	      {!_.isEmpty(flows) && (
120	        <FlexItem>
121	          <Flex direction={{ default: 'row' }}>
122	            {limitReached && (
123	              <FlexItem id="query-summary-warning-icon-container">
124	                <Tooltip content={<Text component={TextVariants.p}>{t('Query limit reached')}</Text>}>
125	                  <InfoCircleIcon className="query-summary-warning" />
126	                </Tooltip>
127	              </FlexItem>
128	            )}
129	            <FlexItem>
130	              <Tooltip
131	                content={
132	                  <Text component={TextVariants.p}>
133	                    {type === 'flowLog' ? t('Filtered flows count') : t('Filtered ended conversations count')}
134	                  </Text>
135	                }
136	              >
137	                <Text id="flowsCount" component={TextVariants.p}>
138	                  {valueFormat(
139	                    filteredFlows!.length,
140	                    0,
141	                    type === 'flowLog' ? t('Flows') : t('Ended conversations'),
142	                    limitReached,
143	                    true
144	                  )}
145	                </Text>
146	              </Tooltip>
147	            </FlexItem>
148	          </Flex>
149	        </FlexItem>
150	      )}
151	      {counters()}
152	      {direction === 'row' && toggleQuerySummary && (
153	        <FlexItem>
154	          <Text id="query-summary-toggle" component={TextVariants.a} onClick={toggleQuerySummary}>
155	            {isShowQuerySummary ? t('See less') : t('See more')}
156	          </Text>
157	        </FlexItem>
158	      )}
159	    </Flex>
160	  );
161	};
162	
163	export default FlowsQuerySummaryContent;

